const fs = require('fs');

function readInts(line) {
  const trimmed = (line ?? '').trim();
  if (trimmed === '') return [];
  return trimmed.split(/\s+/).map((v) => Number.parseInt(v, 10));
}

function main() {
  const input = fs.readFileSync(0, 'utf8').split(/\r?\n/);
  const n = Number.parseInt((input[0] ?? '0').trim(), 10);
  const nums = readInts(input[1] ?? '').slice(0, n);
  const k = Number.parseInt((input[2] ?? '0').trim(), 10);

  const freq = new Map();
  for (const x of nums) {
    freq.set(x, (freq.get(x) ?? 0) + 1);
  }

  const Solution = require('./Solution');
  const sol = new Solution();
  const res = sol.topKFrequent(nums, k);

  if (!Array.isArray(res) || res.length !== k) {
    process.stdout.write('invalid');
    return;
  }

  const out = res.map((v) => Number.parseInt(String(v), 10));
  if (out.some((v) => !Number.isFinite(v))) {
    process.stdout.write('invalid');
    return;
  }

  const set = new Set(out);
  if (set.size !== out.length) {
    process.stdout.write('invalid');
    return;
  }

  out.sort((a, b) => {
    const fa = freq.get(a) ?? 0;
    const fb = freq.get(b) ?? 0;
    if (fa !== fb) return fb - fa;
    return a - b;
  });

  process.stdout.write(out.join(' '));
}

main();

