  if (trimmed === '') return [];
  return trimmed.split(/s+/).map((v) => Number.parseInt(v, 10));
}

function main() {
  const input = fs.readFileSync(0, 'utf8').split(/?
/);
  const n = Number.parseInt((input[0] ?? '0').trim(), 10);
  const temps = readInts(input[1] ?? '').slice(0, n);

  const Solution = require('./Solution');
  const sol = new Solution();
  const result = sol.dailyTemperatures(temps);

  if (!Array.isArray(result) || result.length !== n) {
    process.stdout.write('invalid');
    return;
  }

  process.stdout.write(result.map((x) => Number.parseInt(String(x), 10)).join(' '));
}

main();
